def merge_ranges(pairs):
    merged = sorted(pairs, key=lambda x: x[0])
    current_range = merged[0]

    for next_range in merged[1:]:
        if next_range[0] <= current_range[1]:
            current_range[1] = max(current_range[1], next_range[1])
        else:
            pairs.append(current_range)
            current_range = next_range
    pairs.append(current_range)
    return pairs
